# apply_v0_2_character_creator.py
# Out of Spoons v0.2 encoding-safe updater
# Run inside C:\OutOfSpoons: python apply_v0_2_character_creator.py
from pathlib import Path
import base64

FILES = [
    ('js/data/traitsData.js', ''),
    ('js/systems/characterSystem.js', ''),
    ('js/ui/screens/characterCreatorScreen.js', ''),
    ('css/style.css', ''),
    ('js/state/saveManager.js', ''),
    ('js/systems/dayCycle.js', ''),
    ('js/ui/uiManager.js', ''),
    ('js/ui/screens/mainMenuScreen.js', ''),
    ('js/ui/screens/gameScreen.js', ''),

]

root = Path.cwd()
print(f'Applying Out of Spoons v0.2 in: {root}')
for rel, b64 in FILES:
    target = root / rel
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_bytes(base64.b64decode(b64))
    print('wrote', rel)
print('Done. Start server: python -m http.server 8000')
